import React, { useState, useCallback, useMemo } from 'react';
import {
  Button,
  dispatchAppToast,
  LinPageLayout,
  useCatalogTableBusy,
} from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ktService } from '../../../services/kt/ktService';
import type { AccountingPeriodDto } from '../../../services/kt/models';
import { periodPageLabels as L } from '../../../constants/periodPageLabels';
import { formatDateTimeLocal } from '../../../utils/formatters';
import { getApiErrorMessage } from '../../../utils/getApiErrorMessage';
import { accountingPeriodStatusLabel } from '../../../utils/accountingPeriodStatusLabel';
import erp from '../../../styles/erpPage.module.css';

const TEST_ID = 'erp-ky-ke-toan';
const PAGE_ID = 'kt-ky';
const labels = L.kyKeToan;

const KyKeToanPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [items, setItems] = useState<AccountingPeriodDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [acting, setActing] = useState<string | null>(null);

  const load = useCallback(() => {
    setLoading(true);
    ktService.getPeriods()
      .then(setItems)
      .catch(err => dispatchAppToast(dispatch, { message: getApiErrorMessage(err, labels.loadError), type: 'error' }))
      .finally(() => setLoading(false));
  }, [dispatch]);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => { if (!cancelled) load(); }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [load]);

  const handleClose = async (id: string) => {
    setActing(id);
    try {
      await ktService.closePeriod(id);
      dispatchAppToast(dispatch, { message: labels.closeSuccess, type: 'success' });
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, labels.closeError), type: 'error' });
    } finally {
      setActing(null);
    }
  };

  const handleLock = async (id: string) => {
    setActing(id);
    try {
      await ktService.lockPeriod(id);
      dispatchAppToast(dispatch, { message: labels.lockSuccess, type: 'success' });
      load();
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, labels.lockError), type: 'error' });
    } finally {
      setActing(null);
    }
  };

  const { showTableLoading } = useCatalogTableBusy(loading);

  const catalogToolbar = useMemo(
    () => ({
      testIdPrefix: TEST_ID,
      onRefresh: load,
    }),
    [load],
  );

  const listBody = !showTableLoading && items.length === 0 ? (
    <div className={erp.empty} data-testid={`${TEST_ID}-empty`}>{labels.empty}</div>
  ) : !showTableLoading ? (
    <div className={erp.tableWrapper} data-testid={`${TEST_ID}-table`}>
      <table className={erp.table}>
        <thead><tr><th>{labels.colMonth}</th><th>{labels.colYear}</th><th>{labels.colStatus}</th><th>{labels.colClosedAt}</th><th>{labels.colLockedAt}</th><th /></tr></thead>
        <tbody>{items.map(p => (
          <tr key={p.id} data-testid={`${TEST_ID}-row-${p.id}`}>
            <td>{p.month}</td>
            <td>{p.year}</td>
            <td><span className={erp.tagDefault}>{accountingPeriodStatusLabel(p.status)}</span></td>
            <td>{p.closedAt ? formatDateTimeLocal(p.closedAt) : '—'}</td>
            <td>{p.lockedAt ? formatDateTimeLocal(p.lockedAt) : '—'}</td>
            <td className={erp.colActions}>
              {p.status === 'Open' && (
                <Button size="sm" onClick={() => handleClose(p.id)} loading={acting === p.id} data-testid={`${TEST_ID}-close-${p.id}`}>
                  {labels.closeBtn}
                </Button>
              )}
              {p.status === 'Closed' && (
                <Button size="sm" variant="secondary" onClick={() => handleLock(p.id)} loading={acting === p.id} data-testid={`${TEST_ID}-lock-${p.id}`}>
                  {labels.lockBtn}
                </Button>
              )}
            </td>
          </tr>
        ))}</tbody>
      </table>
    </div>
  ) : null;

  return (
    <div
      className={erp.voucherListRoot}
      data-voucher-list-page
      data-catalog-list-page
      data-testid={`${TEST_ID}-list`}
    >
      <LinPageLayout
        kind="catalog"
        testIdPrefix={TEST_ID}
        pageId={PAGE_ID}
        pageClassName={`${erp.catalogListPage} ${erp.voucherListPage}`}
        header={{
          title: labels.title,
          titleIconClass: 'fas fa-calendar-alt',
          pageId: PAGE_ID,
        }}
        catalogToolbar={catalogToolbar}
        listTitle={labels.listTitle}
        showTableLoading={showTableLoading}
        skeletonRows={8}
      >
        {listBody}
      </LinPageLayout>
    </div>
  );
};

export default KyKeToanPage;
